class Solution {
    public String maximumBinaryString(String binary) {
        char[] chars = binary.toCharArray();
        int zeroCount = 0;
        for (int i = 0; i < chars.length; i++) {
            if (chars[i] == '0') {
                zeroCount++;
            } else {
                zeroCount = 0;
            }
            if (zeroCount >= 3) {
                chars[i - 2] = '1';
                zeroCount = 0;
            }
        }
        return new String(chars);
    }
}
